<?php include 'connexion.php'; ?><?php include 'header.php'; ?><div class="form-container"><h2>Ajouter Médecin</h2><form method="POST">Nom: <input type="text" name="nom"><br><div class="form-group">    <label>Spécialité</label>    <select name="spec" required>        <option value="">-- Choisir une spécialité --</option>        <?php        $req = oci_parse($conn, "SELECT TRIM(SPEC) AS SPEC FROM SPECIALITE ORDER BY SPEC");        oci_execute($req);        while ($p = oci_fetch_assoc($req)) {            echo "<option value='".htmlspecialchars($p['SPEC'], ENT_QUOTES)."'>"                 .htmlspecialchars($p['SPEC'])."</option>";        }        ?>    </select></div>Capacité/jour: <input type="number" name="cap"><br><input type="submit" value="Ajouter"></form><?phpif ($_POST) {    $sql = "INSERT INTO MEDECIN VALUES (SEQ_MEDECIN.NEXTVAL, :nom, :spec, :cap)";    $stid = oci_parse($conn, $sql);    oci_bind_by_name($stid, ":nom", $_POST['nom']);    oci_bind_by_name($stid, ":spec", $_POST['spec']);    oci_bind_by_name($stid, ":cap", $_POST['cap']);    oci_execute($stid);    echo "<p style='color:green;'>Médecin ajouté</p>";}?></div><?php include 'footer.php'; ?>